patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..67bffa97dd48 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3326,6 +3326,26 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
     }
     break;
   case Instruction::Add: {
+    // icmp eq (add (zext X), (zext Y)), 1 -> xor X, Y
+    // icmp ne (add (zext X), (zext Y)), 1 -> not (xor X, Y)
+    // where X and Y are i1 values.
+    // This is valid because:
+    // - If both X and Y are 0: sum = 0, (0 == 1) = false, xor = 0
+    // - If X=0, Y=1 or X=1, Y=0: sum = 1, (1 == 1) = true, xor = 1
+    // - If both X and Y are 1: sum = 2, (2 == 1) = false, xor = 0
+    Value *X, *Y;
+    if (C.isOne() &&
+        match(BOp0, m_ZExt(m_Value(X))) &&
+        match(BOp1, m_ZExt(m_Value(Y))) &&
+        X->getType()->isIntegerTy(1) &&
+        Y->getType()->isIntegerTy(1)) {
+      Value *Xor = Builder.CreateXor(X, Y);
+      if (Pred == ICmpInst::ICMP_EQ)
+        return replaceInstUsesWith(Cmp, Xor);
+      else // ICMP_NE
+        return BinaryOperator::CreateNot(Xor);
+    }
+
     // (A + C2) == C --> A == (C - C2)
     // (A + C2) != C --> A != (C - C2)
     // TODO: Remove the one-use limitation? See discussion in D58633.
@@ -4667,7 +4687,103 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
   // icmp sle (A + 1), Op1 -> icmp slt A, Op1
   if (A && NoOp0WrapProblem && Pred == CmpInst::ICMP_SLE && match(B, m_One()))
     return new ICmpInst(CmpInst::ICMP_SLT, A, Op1);
+  // icmp eq/ne (zext A) + (zext B), 1 -> xor A, B
+  // icmp eq/ne (zext A) + (zext B), 0 -> nor A, B (i.e., xor (or A, B), true)
+  // icmp eq/ne (zext A) + (zext B), 2 -> and A, B
+  // icmp eq/ne (sext A) + (sext B), -1 -> xor A, B
+  // icmp eq/ne (sext A) + (sext B), 0 -> nor A, B
+  // icmp eq/ne (sext A) + (sext B), -2 -> and A, B
+  if (A && B && (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_NE)) {
+    Value *X = nullptr, *Y = nullptr;
+    // Check for zext pattern
+    if (match(A, m_ZExt(m_Value(X))) && match(B, m_ZExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) && Y->getType()->isIntOrIntVectorTy(1)) {
+      Value *Result = nullptr;
+      if (match(Op1, m_One())) {
+        // icmp eq/ne (zext A) + (zext B), 1 -> xor A, B
+        Result = Builder.CreateXor(X, Y);
+      } else if (match(Op1, m_Zero())) {
+        // icmp eq/ne (zext A) + (zext B), 0 -> nor A, B
+        Value *Or = Builder.CreateOr(X, Y);
+        Result = Builder.CreateNot(Or);
+      } else {
+        const APInt *C;
+        if (match(Op1, m_APInt(C)) && C->isIntN(2) && C->uge(2)) {
+          // icmp eq/ne (zext A) + (zext B), 2 -> and A, B
+          Result = Builder.CreateAnd(X, Y);
+        }
+      }
+      if (Result) {
+        if (Pred == ICmpInst::ICMP_NE)
+          Result = Builder.CreateNot(Result);
+        return replaceInstUsesWith(I, Result);
+      }
+    }
+    // Check for sext pattern
+    if (match(A, m_SExt(m_Value(X))) && match(B, m_SExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) && Y->getType()->isIntOrIntVectorTy(1)) {
+      Value *Result = nullptr;
+      const APInt *C;
+      if (match(Op1, m_APInt(C))) {
+        if (C->isAllOnes()) {
+          // icmp eq/ne (sext A) + (sext B), -1 -> xor A, B
+          Result = Builder.CreateXor(X, Y);
+        } else if (C->isZero()) {
+          // icmp eq/ne (sext A) + (sext B), 0 -> nor A, B
+          Value *Or = Builder.CreateOr(X, Y);
+          Result = Builder.CreateNot(Or);
+        } else if (C->isSignedIntN(2) && *C == -2) {
+          // icmp eq/ne (sext A) + (sext B), -2 -> and A, B
+          Result = Builder.CreateAnd(X, Y);
+        }
+      }
+      if (Result) {
+        if (Pred == ICmpInst::ICMP_NE)
+          Result = Builder.CreateNot(Result);
+        return replaceInstUsesWith(I, Result);
+      }
+    }
+  }

+  // icmp eq/ne (zext A) + (zext B), 2 -> and A, B
+  if (A && B && match(Op1, m_SpecificInt(2)) && (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_NE)) {
+    Value *X = nullptr, *Y = nullptr;
+    if (match(A, m_ZExt(m_Value(X))) && match(B, m_ZExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) && Y->getType()->isIntOrIntVectorTy(1)) {
+      Value *And = Builder.CreateAnd(X, Y);
+      if (Pred == ICmpInst::ICMP_NE)
+        And = Builder.CreateNot(And);
+      return replaceInstUsesWith(I, And);
+    }
+  }
+
+  // icmp eq/ne (sext A) + (sext B), -2 -> and A, B
+  if (A && B && match(Op1, m_SpecificInt(-2)) && (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_NE)) {
+    Value *X = nullptr, *Y = nullptr;
+    if (match(A, m_SExt(m_Value(X))) && match(B, m_SExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) && Y->getType()->isIntOrIntVectorTy(1)) {
+      Value *And = Builder.CreateAnd(X, Y);
+      if (Pred == ICmpInst::ICMP_NE)
+        And = Builder.CreateNot(And);
+      return replaceInstUsesWith(I, And);
+    }
+  }
+
+  // icmp eq/ne (sext A) + (sext B), -1 -> xor A, B
+  if (A && B && match(Op1, m_AllOnes()) && (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_NE)) {
+    Value *X = nullptr, *Y = nullptr;
+    if (match(A, m_SExt(m_Value(X))) && match(B, m_SExt(m_Value(Y))) &&
+        X->getType()->isIntOrIntVectorTy(1) && Y->getType()->isIntOrIntVectorTy(1)) {
+      Value *Xor = Builder.CreateXor(X, Y);
+      if (Pred == ICmpInst::ICMP_NE)
+        Xor = Builder.CreateNot(Xor);
+      return replaceInstUsesWith(I, Xor);
+    }
+  }
+
+  // icmp slt (A + -1), Op1 -> icmp sle A, Op1
+
+  // icmp slt (A + -1), Op1 -> icmp sle A, Op1
   // icmp sgt (A + 1), Op1 -> icmp sge A, Op1
   if (A && NoOp0WrapProblem && Pred == CmpInst::ICMP_SGT && match(B, m_One()))
     return new ICmpInst(CmpInst::ICMP_SGE, A, Op1);

